// Black Hole — Particle Simulation
//
// Simulates particles orbiting under Schwarzschild gravity.
// Particles spawn at the outer disk edge, spiral inward, get consumed at horizon.
// Uses Verlet integration for energy conservation.
//
// Particle layout (64 bytes, matches compute_common.rs Particle struct):
//   position: vec3<f32> + pad
//   velocity: vec3<f32> + life: f32
//   age: f32 + pad[3]
//   color: vec4<f32>

struct Particle {
    position: vec3<f32>,
    velocity: vec3<f32>,
    life:     f32,
    age:      f32,
    color:    vec4<f32>,
};

struct SimUniforms {
    active_count: u32,
    frame_count: u32,
    disk_inner: f32,
    disk_outer: f32,
    speed: f32,
    turbulence: f32,
    time_val: f32,
    dt: f32,
    inject_burst: f32,
    _pad0: f32,
    _pad1: f32,
    _pad2: f32,
};

@group(0) @binding(0) var<storage, read_write> particles: array<Particle>;
@group(0) @binding(1) var<uniform> params: SimUniforms;

// Wang hash (matches particle_common.wgsl)
fn wang_hash(seed_in: u32) -> u32 {
    var seed = seed_in;
    seed = (seed ^ 61u) ^ (seed >> 16u);
    seed = seed * 9u;
    seed = seed ^ (seed >> 4u);
    seed = seed * 0x27d4eb2du;
    seed = seed ^ (seed >> 15u);
    return seed;
}

fn hash_float(seed: u32) -> f32 {
    return f32(wang_hash(seed)) / 4294967296.0;
}

fn hash_float3(seed: u32) -> vec3<f32> {
    let h0 = wang_hash(seed);
    let h1 = wang_hash(h0);
    let h2 = wang_hash(h1);
    return vec3<f32>(
        f32(h0) / 4294967296.0,
        f32(h1) / 4294967296.0,
        f32(h2) / 4294967296.0,
    );
}

// Simplex noise 2D (simplified — matching fluid sim pattern)
const SIMPLEX_GRAD2_X: array<f32, 8> = array<f32, 8>(
    1.0, 0.7071, 0.0, -0.7071, -1.0, -0.7071, 0.0, 0.7071
);
const SIMPLEX_GRAD2_Y: array<f32, 8> = array<f32, 8>(
    0.0, 0.7071, 1.0, 0.7071, 0.0, -0.7071, -1.0, -0.7071
);

fn simplex_noise_2d(v: vec2<f32>) -> f32 {
    let F2: f32 = 0.36602540378;
    let G2: f32 = 0.21132486540;
    let s = (v.x + v.y) * F2;
    let i = floor(v + s);
    let t = (i.x + i.y) * G2;
    let x0 = v - (i - t);
    let i1 = select(vec2<f32>(0.0, 1.0), vec2<f32>(1.0, 0.0), x0.x > x0.y);
    let x1 = x0 - i1 + G2;
    let x2 = x0 - 1.0 + 2.0 * G2;
    let h0 = wang_hash(u32(i.x + 10000.0) * 73856093u ^ u32(i.y + 10000.0) * 19349663u);
    let h1 = wang_hash(u32(i.x + i1.x + 10000.0) * 73856093u
        ^ u32(i.y + i1.y + 10000.0) * 19349663u);
    let h2 = wang_hash(u32(i.x + 1.0 + 10000.0) * 73856093u
        ^ u32(i.y + 1.0 + 10000.0) * 19349663u);
    let g0 = vec2<f32>(SIMPLEX_GRAD2_X[h0 & 7u], SIMPLEX_GRAD2_Y[h0 & 7u]);
    let g1 = vec2<f32>(SIMPLEX_GRAD2_X[h1 & 7u], SIMPLEX_GRAD2_Y[h1 & 7u]);
    let g2 = vec2<f32>(SIMPLEX_GRAD2_X[h2 & 7u], SIMPLEX_GRAD2_Y[h2 & 7u]);
    let t0 = 0.5 - dot(x0, x0);
    let t1 = 0.5 - dot(x1, x1);
    let t2 = 0.5 - dot(x2, x2);
    let n0 = select(0.0, t0 * t0 * t0 * t0 * dot(g0, x0), t0 >= 0.0);
    let n1 = select(0.0, t1 * t1 * t1 * t1 * dot(g1, x1), t1 >= 0.0);
    let n2 = select(0.0, t2 * t2 * t2 * t2 * dot(g2, x2), t2 >= 0.0);
    return clamp((n0 + n1 + n2) * 35.0 + 0.5, 0.0, 1.0);
}

// Spawn a new particle anywhere across the disk so respawned particles
// repopulate the inner regions, not just the outer rim. Without this,
// the entire population eventually concentrates in the outer 20% of
// the disk (because the original spawn zone was 0.8..1.0 of outer).
fn spawn_particle(idx: u32) -> Particle {
    let seed = wang_hash(idx * 1099u + u32(params.time_val * 60.0) * 7919u);
    let rng = hash_float3(seed);

    // Random angle in disk plane
    let angle = rng.x * 6.2831853;
    // Random radius across the full disk (linear in r — gives roughly
    // even visual density, since outer regions have more area but we
    // want the inner regions to remain populated).
    let spawn_r = params.disk_inner + rng.y * (params.disk_outer - params.disk_inner);
    // Slight vertical spread, scaled by radius so it matches disk thickness
    let y_offset = (rng.z - 0.5) * 0.1 * spawn_r;

    let pos = vec3<f32>(
        cos(angle) * spawn_r,
        y_offset,
        sin(angle) * spawn_r,
    );

    // Orbital velocity: v_circular = sqrt(0.5 * rs / r) for Schwarzschild (rs = 1)
    // Tangential direction (perpendicular to radial, in disk plane)
    let v_orbital = sqrt(0.5 / spawn_r);
    let tangent = vec3<f32>(-sin(angle), 0.0, cos(angle));

    // Add slight inward drift to spiral
    let radial = normalize(vec3<f32>(pos.x, 0.0, pos.z));
    let vel = tangent * v_orbital - radial * v_orbital * 0.02;

    var p: Particle;
    p.position = pos;
    p.velocity = vel;
    p.life = 1.0;
    p.age = 0.0;
    // Temperature color: will be overridden by display based on radius
    p.color = vec4<f32>(1.0, 0.7, 0.3, 1.0);
    return p;
}

@compute @workgroup_size(256)
fn simulate(@builtin(global_invocation_id) gid: vec3<u32>) {
    let idx = gid.x;
    if idx >= params.active_count {
        return;
    }

    var p = particles[idx];

    // Dead particle — respawn
    if p.life < 0.5 {
        p = spawn_particle(idx);
        particles[idx] = p;
        return;
    }

    let pos = p.position;
    let r = length(pos);
    let dt = params.dt * params.speed;

    // ── Schwarzschild gravity ──
    // Newtonian + GR correction for stable orbits
    // a = -GM/r³ * pos + GR_correction
    // In our units (rs = 1, GM = 0.5):
    let r2 = r * r;
    let r3 = r2 * r;
    let gravity = -0.5 / r3 * pos;

    // GR correction: perihelion precession term (3 * rs * L² / (2 * r⁵))
    // This creates the characteristic frame-dragging spiral
    let L_vec = cross(pos, p.velocity);
    let L2 = dot(L_vec, L_vec);
    let gr_correction = -1.5 * L2 / (r2 * r3) * pos;

    let total_accel = gravity + gr_correction;

    // ── Turbulence (curl noise in disk plane) ──
    let noise_scale = 3.0;
    let angle = atan2(pos.z, pos.x);
    let n1 = simplex_noise_2d(vec2<f32>(
        angle * noise_scale + params.time_val * 0.2,
        r * noise_scale * 0.5,
    ));
    let n2 = simplex_noise_2d(vec2<f32>(
        r * noise_scale * 0.3 + params.time_val * 0.15,
        angle * noise_scale * 1.5 + 100.0,
    ));
    // Curl: perpendicular to gradient
    let turb_radial = (n1 - 0.5) * 2.0;
    let turb_tangential = (n2 - 0.5) * 2.0;
    let radial_dir = normalize(vec3<f32>(pos.x, 0.0, pos.z) + vec3<f32>(1e-8));
    let tangent_dir = vec3<f32>(-radial_dir.z, 0.0, radial_dir.x);
    let turbulence_force = (radial_dir * turb_radial + tangent_dir * turb_tangential
        + vec3<f32>(0.0, (n1 - 0.5) * 0.5, 0.0))
        * params.turbulence * 0.01;

    // ── Disk confinement (soft push toward y=0) ──
    // Moderate pull — particles bob meaningfully above and below the
    // plane (so the two-layer top/bottom split has signal), but they
    // don't drift so far that they leave the disk's volumetric extent.
    // The scatter shader culls particles outside |y| < 0.24*r anyway,
    // so this just keeps the population concentrated where it counts.
    let disk_push = vec3<f32>(0.0, -pos.y * 1.5, 0.0);

    // ── Velocity update (Verlet) ──
    p.velocity += (total_accel + turbulence_force + disk_push) * dt;

    // Light damping to prevent energy buildup from turbulence
    p.velocity *= 0.9995;

    // ── Position update ──
    p.position += p.velocity * dt;

    // ── Age ──
    p.age += params.dt;

    // ── Kill conditions ──
    let new_r = length(p.position);
    // Consumed by event horizon
    if new_r < 1.2 {
        p.life = 0.0;
    }
    // Escaped too far
    if new_r > params.disk_outer * 2.0 {
        p.life = 0.0;
    }
    // No age cap. Particles live until they actually fall into the hole
    // or escape — killing healthy orbiting particles by age was emptying
    // the inner disk, since freshly-respawned particles take time to
    // spiral inward and the old spawn zone (0.8..1.0 of outer) meant
    // nothing ever populated the inner radii in the first place.

    // ── Color based on radius (temperature) ──
    let t = clamp((new_r - params.disk_inner) / (params.disk_outer - params.disk_inner), 0.0, 1.0);
    let inner_col = vec3<f32>(1.0, 0.95, 0.85);
    let mid_col = vec3<f32>(1.0, 0.55, 0.15);
    let outer_col = vec3<f32>(0.6, 0.12, 0.02);
    var col: vec3<f32>;
    if t < 0.5 {
        col = mix(inner_col, mid_col, t * 2.0);
    } else {
        col = mix(mid_col, outer_col, (t - 0.5) * 2.0);
    }
    // Brighten particles near horizon (gravitational blueshift / heating)
    let heat = exp(-(new_r - 1.5) * 0.5) * 2.0;
    col += vec3<f32>(0.5, 0.3, 0.1) * heat;

    p.color = vec4<f32>(col, 1.0);

    particles[idx] = p;
}

// Black Hole — Polar Particle Scatter
//
// Splatters particle positions onto a 2D polar-mapped density texture.
//   X axis = angle (0..2π → 0..width)
//   Y axis = radius (disk_inner..disk_outer → 0..height)

struct Particle {
    position: vec3<f32>,
    velocity: vec3<f32>,
    life:     f32,
    age:      f32,
    color:    vec4<f32>,
};

struct ScatterUniforms {
    active_count: u32,
    tex_w: u32,
    tex_h: u32,
    scaled_energy: u32,
    disk_inner: f32,
    disk_outer: f32,
    _pad0: f32,
    _pad1: f32,
};

@group(0) @binding(0) var<storage, read> particles: array<Particle>;
@group(0) @binding(1) var<storage, read_write> accum_top: array<atomic<u32>>;
@group(0) @binding(2) var<storage, read_write> accum_bottom: array<atomic<u32>>;
@group(0) @binding(3) var<uniform> params: ScatterUniforms;

@compute @workgroup_size(256)
fn splat(@builtin(global_invocation_id) gid: vec3<u32>) {
    if gid.x >= params.active_count {
        return;
    }

    let p = particles[gid.x];
    if p.life < 0.5 {
        return;
    }

    let pos = p.position;
    let r = length(vec2<f32>(pos.x, pos.z));

    if r < params.disk_inner || r > params.disk_outer {
        return;
    }

    // Vertical cull. The deflection bake's volumetric integral uses a
    // Gaussian profile with half-thickness 0.12*r — beyond ~2 sigma the
    // contribution is negligible. Without this cull, particles that
    // drift far above or below the plane still splat into their (angle,
    // radius) cell and create phantom radial streaks because they
    // persistently illuminate a single polar column from outside the
    // disk volume.
    let half_thick = 0.24 * r;
    if abs(pos.y) > half_thick {
        return;
    }

    let angle = atan2(pos.z, pos.x) + 3.14159265;
    let angle_norm = angle / 6.28318530;
    let r_norm = (r - params.disk_inner) / (params.disk_outer - params.disk_inner);

    let px = u32(angle_norm * f32(params.tex_w)) % params.tex_w;
    let py = u32(r_norm * f32(params.tex_h)) % params.tex_h;
    let idx = py * params.tex_w + px;

    // Two-layer polar: split by signed disk-plane height. Particles above the
    // plane go into the top texture, below go into the bottom. The display
    // shader blends them with a bias so each disk crossing favors its own
    // side, giving the disk a sense of thickness.
    if pos.y >= 0.0 {
        atomicAdd(&accum_top[idx], params.scaled_energy);
    } else {
        atomicAdd(&accum_bottom[idx], params.scaled_energy);
    }
}

// Black Hole — Kerr Deflection Map
//
// Traces null geodesics in Kerr spacetime (spinning black hole).
// At spin=0, reduces exactly to Schwarzschild.
//
// Physics:
//   - Schwarzschild gravitational acceleration: -1.5 h²/r⁵ pos
//   - Kerr frame-dragging: gravitomagnetic force a/r³ cross(ŷ, vel)
//   - Boyer-Lindquist radius for horizon check (oblate geometry)
//   - Event horizon: r_H = 0.5(1 + √(1 - a²)) in our units (r_s = 1)
//
// Output 1: (final_r, disk1_r, cos_angle1, sin_angle1)
// Output 2: (vol_accum, disk2_r, cos_angle2, sin_angle2)
// Output 3: (sky_dir.xyz, escaped_flag)

struct Uniforms {
    aspect: f32,
    cam_dist: f32,
    tilt_rad: f32,
    rotate_rad: f32,
    steps: f32,
    uv_scale: f32,
    spin: f32,
    cam_velocity: f32,
    cam_freefall: f32,
    _pad0: f32,
    _pad1: f32,
    _pad2: f32,
};

@group(0) @binding(0) var<uniform> u: Uniforms;
@group(0) @binding(1) var output1: texture_storage_2d<rgba16float, write>;
@group(0) @binding(2) var output2: texture_storage_2d<rgba16float, write>;
@group(0) @binding(3) var output3: texture_storage_2d<rgba16float, write>;

// Fixed generous crossing bounds — covers full param ranges
const CROSS_INNER: f32 = 0.5;
const CROSS_OUTER: f32 = 25.0;

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) gid: vec3<u32>) {
    let dims = textureDimensions(output1);
    if gid.x >= dims.x || gid.y >= dims.y {
        return;
    }

    let uv = (vec2<f32>(f32(gid.x), f32(gid.y)) + 0.5) / vec2<f32>(f32(dims.x), f32(dims.y));
    let ndc = (uv * 2.0 - 1.0) * u.uv_scale;
    let screen = vec2<f32>(ndc.x * u.aspect, -ndc.y);

    // ── Kerr spin setup (needed up front for camera physics horizon clamp) ──
    let a = u.spin;
    let a2 = a * a;
    // Event horizon: r_H = M + √(M² - a²M²) where M=0.5 (r_s = 1)
    // = 0.5(1 + √(1 - a²))
    let r_horizon = 0.5 * (1.0 + sqrt(max(1.0 - a2, 0.0)));
    let spin_axis = vec3<f32>(0.0, 1.0, 0.0);

    // ── Camera physics ──
    // The camera is allowed to fly through the event horizon for the trippy
    // "fall into a black hole" effect. The clamp here is purely numerical
    // safety to keep ratios finite very near the singularity — physical
    // correctness is not enforced inside the horizon (real observers can't
    // hover there, but this is a visual tool).
    let safe_cam_dist = max(u.cam_dist, 0.05);
    let camera_inside_horizon = safe_cam_dist < r_horizon;

    // ZAMO (Zero Angular Momentum Observer) frame correction.
    // Outside the horizon: the proper-frame solid angle subtended by infinity
    // shrinks by ≈ √(1 − r_s/r), so the aperture widens by 1/that to keep
    // distant features at a consistent angular size as the camera descends.
    // Inside the horizon: 1 − r_s/r is negative, the max() floor keeps the
    // metric factor at its minimum (0.05), giving a fully-saturated wide
    // aperture (~5×) for the "fallen in" view.
    let metric_factor = sqrt(max(1.0 - 1.0 / safe_cam_dist, 0.05));
    let fov_factor = 1.2 / metric_factor;

    // Gravitational redshift between observer at safe_cam_dist and infinity.
    // Stored multiplied into final_r so the display pass can dim escaping
    // light by the correct amount when the camera is deep in the well.
    let redshift_factor = metric_factor;

    let cos_tilt = cos(u.tilt_rad);
    let sin_tilt = sin(u.tilt_rad);
    let cos_rot = cos(u.rotate_rad);
    let sin_rot = sin(u.rotate_rad);

    let cam_pos = vec3<f32>(
        safe_cam_dist * cos_tilt * cos_rot,
        safe_cam_dist * sin_tilt,
        safe_cam_dist * cos_tilt * sin_rot,
    );
    let fwd = normalize(-cam_pos);
    let world_up = vec3<f32>(0.0, 1.0, 0.0);
    let right = normalize(cross(fwd, world_up));
    let up = cross(right, fwd);

    var ray_dir = normalize(fwd + screen.x * right * fov_factor + screen.y * up * fov_factor);

    // ── Relativistic aberration ──
    // Compose ZAMO → freefall-observer frame with a pure SR boost.
    // The observer's velocity is radial-inward (v̂ = fwd). In the
    // moving observer's frame, rays are pulled toward the forward
    // direction, so to convert a moving-frame ray to its ZAMO-frame
    // equivalent we use the INVERSE aberration transform:
    //
    //     cos θ = (cos θ' − β) / (1 − β cos θ')
    //
    // where θ is the angle between the ray and v̂ in the ZAMO frame
    // and θ' is the same angle in the moving frame.
    //
    // Cinematic mode: β = user slider (cam_velocity).
    // Freefall mode: β = √(r_s/r) (radial infall from rest at infinity),
    // clamped to 0.99 to keep the formula well-defined.
    var beta = u.cam_velocity;
    if u.cam_freefall > 0.5 {
        beta = clamp(sqrt(1.0 / safe_cam_dist), 0.0, 0.99);
    }
    if beta > 1e-4 {
        let v_dir = fwd; // radial-inward at cam_pos
        let cos_tp = dot(ray_dir, v_dir);
        let denom = 1.0 - beta * cos_tp;
        let cos_t = (cos_tp - beta) / denom;
        // Perpendicular component scaling: sin θ / sin θ'. Derivable
        // from requiring |ray_dir_static| = 1.
        let sin_tp2 = max(1.0 - cos_tp * cos_tp, 0.0);
        let sin_t2 = max(1.0 - cos_t * cos_t, 0.0);
        let perp_scale = select(
            1.0,
            sqrt(sin_t2 / sin_tp2),
            sin_tp2 > 1e-8,
        );
        let ray_perp = ray_dir - v_dir * cos_tp;
        ray_dir = normalize(v_dir * cos_t + ray_perp * perp_scale);
    }

    var pos = cam_pos;
    var vel = ray_dir;
    let h_vec = cross(pos, vel);
    let h2 = dot(h_vec, h_vec);

    let max_steps = i32(u.steps);
    let escape_r = max(safe_cam_dist * 3.0, 40.0);
    let base_step = max(safe_cam_dist * 0.02, 0.15);

    var prev_y = pos.y;
    var final_r = 0.0;
    var absorbed = false;

    var c1_r = 0.0; var c1_ca = 0.0; var c1_sa = 0.0;
    var c2_r = 0.0; var c2_ca = 0.0; var c2_sa = 0.0;
    var crossing_count = 0;
    var vol_accum = 0.0;

    for (var i = 0; i < max_steps; i++) {
        let r = length(pos);

        // Boyer-Lindquist radius (accounts for oblate Kerr horizon geometry)
        let w2 = r * r - a2;
        let r_bl = sqrt(max(0.5 * w2 + sqrt(max(0.25 * w2 * w2
            + a2 * pos.y * pos.y, 0.0)), 1e-8));

        // Singularity check — terminate any ray that reaches the center.
        // This also prevents 1/r⁵ NaNs in the gravitational acceleration.
        if r < 0.1 { final_r = 0.0; absorbed = true; break; }

        // Horizon absorption — only applied when the camera is OUTSIDE the
        // horizon. If the camera is inside, every ray starts inside the
        // horizon by definition, and we don't want them all self-absorbing
        // at step 0; let them fall to the singularity instead.
        if !camera_inside_horizon && r_bl < r_horizon {
            final_r = 0.0; absorbed = true; break;
        }

        if r > escape_r { final_r = r; break; }
        // Early escape: ray well beyond camera and moving outward — negligible bending
        if r > max(safe_cam_dist * 2.0, 15.0) && dot(pos, vel) > 0.0 {
            final_r = r; break;
        }

        let step = base_step * clamp(r * 0.1, 0.005, 2.0);

        // ── Schwarzschild gravitational acceleration ──
        let r2 = r * r;
        let r5 = r2 * r2 * r;
        let accel_grav = -1.5 * h2 / r5 * pos;

        // ── Kerr frame-dragging (gravitomagnetic force) ──
        // Photons are dragged in the direction of black hole rotation.
        // Force ∝ a/r³, direction = cross(spin_axis, vel).
        // At a=0 this is zero → identical to Schwarzschild.
        let r3 = r2 * r;
        let accel_drag = a / r3 * cross(spin_axis, vel);

        let accel = accel_grav + accel_drag;

        // Verlet first half-step
        vel += accel * step * 0.5;
        pos += vel * step;

        // Verlet second half-step (recompute at new position)
        let r_new = length(pos);
        let r2_new = r_new * r_new;
        let r5_new = r2_new * r2_new * r_new;
        let accel_grav2 = -1.5 * h2 / r5_new * pos;
        let r3_new = r2_new * r_new;
        let accel_drag2 = a / r3_new * cross(spin_axis, vel);
        vel += (accel_grav2 + accel_drag2) * step * 0.5;

        // ── Volumetric density accumulation ──
        // Gaussian vertical profile: rays near the disk plane accumulate density.
        // Path integral gives volumetric thickness for edge-on viewing.
        let disk_r_xz = length(vec2<f32>(pos.x, pos.z));
        if disk_r_xz > CROSS_INNER && disk_r_xz < CROSS_OUTER {
            let half_thick = 0.12 * disk_r_xz;
            let y_norm = pos.y / half_thick;
            vol_accum += exp(-y_norm * y_norm * 2.0) * step;
        }

        // ── Disk crossing detection ──
        let cur_y = pos.y;
        if prev_y * cur_y < 0.0 {
            let frac = abs(prev_y) / (abs(prev_y) + abs(cur_y) + 1e-8);
            let cross_pos = pos - vel * step * (1.0 - frac);
            let cross_r = length(cross_pos);

            if cross_r > CROSS_INNER && cross_r < CROSS_OUTER {
                let angle = atan2(cross_pos.z, cross_pos.x);
                let ca = cos(angle);
                let sa = sin(angle);

                if crossing_count == 0 {
                    c1_r = cross_r; c1_ca = ca; c1_sa = sa;
                } else if crossing_count == 1 {
                    c2_r = cross_r; c2_ca = ca; c2_sa = sa;
                }
                crossing_count++;
            }
        }
        prev_y = cur_y;
        final_r = r;
    }

    // Apply gravitational redshift to the escape radius — the photon ring
    // and far-field intensity dim by metric_factor when the camera is deep
    // in the well.
    let final_r_redshifted = final_r * redshift_factor;
    textureStore(output1, gid.xy, vec4<f32>(final_r_redshifted, c1_r, c1_ca, c1_sa));
    textureStore(output2, gid.xy, vec4<f32>(vol_accum, c2_r, c2_ca, c2_sa));

    if absorbed {
        textureStore(output3, gid.xy, vec4<f32>(0.0, 0.0, 0.0, 0.0));
    } else {
        let sky_dir = normalize(vel);
        textureStore(output3, gid.xy, vec4<f32>(sky_dir, 1.0));
    }
}

// Black Hole — Cinematic Display (dual crossing + gravitationally lensed star field)
//
// Deflection map layout:
//   output1: (final_r, disk1_r, cos_angle1, sin_angle1)
//   output2: (vol_accum, disk2_r, cos_angle2, sin_angle2)
//   output3: (sky_dir.xyz, escaped_flag)

struct Uniforms {
    time_val: f32,
    disk_inner: f32,
    disk_outer: f32,
    disk_glow: f32,
    orbit_angle: f32,
    stars_brightness: f32,
    spin: f32,
    particle_strength: f32,
};

@group(0) @binding(0) var<uniform> u: Uniforms;
@group(0) @binding(1) var deflection1: texture_2d<f32>;
@group(0) @binding(2) var deflection2: texture_2d<f32>;
@group(0) @binding(3) var s_linear: sampler;
@group(0) @binding(4) var output: texture_storage_2d<rgba16float, write>;
@group(0) @binding(5) var sky_dir_tex: texture_2d<f32>;
@group(0) @binding(6) var particle_density_top: texture_2d<f32>;
@group(0) @binding(7) var particle_density_bottom: texture_2d<f32>;

// Sample particle density at a disk hit point. Polar coords:
//   X = angle / 2π (wrapped)
//   Y = (r - inner) / (outer - inner) (clamped)
//
// `near_bias` selects which side of the disk plane this hit favors:
//   1.0 = top-biased, 0.0 = bottom-biased. The other side still
//   contributes (at 0.6×) so the disk feels volumetric instead of
//   showing only one face.
//
// The polar density textures are now pre-blurred by a separable
// gaussian compute pass before display reads them, so single-tap
// bilinear sampling is sufficient — no inline blur needed. Inner
// cells still need an area-correction weight because per-cell
// arc length grows with r, and without it inner clumps still spike
// brighter per screen pixel than outer ones for the same particle
// count.
fn sample_particle_density(
    disk_r: f32, cos_a: f32, sin_a: f32, near_bias: f32,
) -> f32 {
    let angle = atan2(sin_a, cos_a);
    let ang_norm = fract(angle / 6.28318530 + 1.0);
    let r_norm = clamp(
        (disk_r - u.disk_inner) / (u.disk_outer - u.disk_inner),
        0.0, 1.0,
    );
    let uv = vec2<f32>(ang_norm, r_norm);
    let d_top = textureSampleLevel(particle_density_top, s_linear, uv, 0.0).r;
    let d_bot = textureSampleLevel(particle_density_bottom, s_linear, uv, 0.0).r;
    let near_w = mix(0.6, 1.0, near_bias);
    let far_w  = mix(1.0, 0.6, near_bias);
    let raw = d_top * near_w + d_bot * far_w;
    let area_w = smoothstep(0.0, 0.4, r_norm);
    return raw * area_w;
}

// ── Hash functions ──

fn hash21(p: vec2<f32>) -> f32 {
    var p3 = fract(vec3<f32>(p.x, p.y, p.x) * 0.1031);
    p3 += dot(p3, p3.yzx + 33.33);
    return fract((p3.x + p3.y) * p3.z);
}

fn noise2d(p: vec2<f32>) -> f32 {
    let i = floor(p);
    let f = fract(p);
    let u2 = f * f * (3.0 - 2.0 * f);
    return mix(
        mix(hash21(i), hash21(i + vec2<f32>(1.0, 0.0)), u2.x),
        mix(hash21(i + vec2<f32>(0.0, 1.0)), hash21(i + vec2<f32>(1.0, 1.0)), u2.x),
        u2.y,
    );
}

fn fbm(p: vec2<f32>) -> f32 {
    var val = noise2d(p) * 0.5;
    val += noise2d(p * 2.03 + vec2<f32>(1.7, -1.3)) * 0.25;
    val += noise2d(p * 4.07 + vec2<f32>(3.4, -2.6)) * 0.125;
    return val;
}

// ── Procedural star field ──

fn star_layer(theta: f32, phi: f32, scale: f32, threshold: f32,
              intensity_mult: f32, seed: f32) -> vec3<f32> {
    let uv = vec2<f32>(phi * scale * 0.15915, theta * scale * 0.31831);
    let cell = floor(uv);
    let f = fract(uv);

    var light = vec3<f32>(0.0);

    for (var j = -1; j <= 1; j++) {
        for (var i = -1; i <= 1; i++) {
            let neighbor = cell + vec2<f32>(f32(i), f32(j));
            let h = hash21(neighbor + seed);
            if h > threshold {
                let sx = hash21(neighbor * 1.273 + seed + 7.0);
                let sy = hash21(neighbor * 2.178 + seed + 13.0);
                let d = f - vec2<f32>(f32(i), f32(j)) - vec2<f32>(sx, sy);
                let dist2 = dot(d, d);

                // Steeper power law — many faint, very few bright
                let norm_bright = (h - threshold) / (1.0 - threshold);
                let star_intensity = pow(norm_bright, 1.5) * intensity_mult;

                // Tight point spread — sharp pinpoints, not blobs
                let core = exp(-dist2 * 6000.0);
                let halo = exp(-dist2 * 800.0) * norm_bright * norm_bright * 0.06;

                // Desaturated spectral colors — subtle tint, mostly white
                let temp = hash21(neighbor * 3.46 + seed + 27.0);
                var star_col: vec3<f32>;
                if temp > 0.82 {
                    star_col = vec3<f32>(0.88, 0.92, 1.15);  // O/B cool blue tint
                } else if temp > 0.55 {
                    star_col = vec3<f32>(0.97, 0.98, 1.05);  // A/F near-white
                } else if temp > 0.25 {
                    star_col = vec3<f32>(1.0, 0.97, 0.93);   // G solar
                } else {
                    star_col = vec3<f32>(1.05, 0.92, 0.82);  // K/M warm tint
                }

                light += star_col * star_intensity * (core + halo);
            }
        }
    }
    return light;
}

fn star_field(dir: vec3<f32>, brightness: f32) -> vec3<f32> {
    if brightness < 0.001 { return vec3<f32>(0.0); }

    let theta = acos(clamp(dir.y, -1.0, 1.0));
    let phi = atan2(dir.z, dir.x) + 3.14159265;

    var stars = vec3<f32>(0.0);

    // Layer 1: bright stars
    stars += star_layer(theta, phi, 20.0, 0.82, 3.0, 0.0);

    // Layer 2: medium density
    stars += star_layer(theta, phi, 50.0, 0.80, 1.2, 100.0);

    // Layer 3: dense field
    stars += star_layer(theta, phi, 100.0, 0.84, 0.5, 200.0);

    // Layer 4: faint background dust
    stars += star_layer(theta, phi, 180.0, 0.88, 0.15, 300.0);

    return stars * brightness;
}

// ── Accretion disk shading ──

fn disk_opacity_from_r(r: f32) -> f32 {
    // Inner edge fades close to horizon for plunging-region glow.
    // Outer edge tightened: previously this fade ran from disk_outer*0.7
    // to disk_outer*1.5, painting a wide warm halo 50% beyond the
    // nominal radius. Against bright stars the halo became a visible
    // "thicker band outside the disk". Tightened to (0.95, 1.05) so
    // the disk ends close to disk_outer with just enough antialiasing
    // softness to avoid a hard pixel edge.
    let inner_fade = smoothstep(u.disk_inner * 0.25, u.disk_inner * 1.3, r);
    let outer_fade = 1.0 - smoothstep(u.disk_outer * 0.95, u.disk_outer * 1.05, r);
    return inner_fade * outer_fade;
}

fn shade_disk(disk_r: f32, cos_a: f32, sin_a: f32, is_secondary: bool) -> vec3<f32> {
    let disk_range = u.disk_outer - u.disk_inner;
    let t = clamp((disk_r - u.disk_inner) / disk_range, 0.0, 1.0);
    let ring_r = t;
    // Compute r_norm normally — DO NOT clamp. The previous max(.., 1.0)
    // clamp produced a step function at the boundary that turned
    // ripples in the gaussian-blurred c1_r into radial brightness
    // spikes around the silhouette. Brightness is bounded at the END
    // of this function with a smooth output cap that preserves the
    // continuity of r_falloff across the boundary.
    let r_norm = disk_r / u.disk_inner;

    // Reconstruct angle
    let base_angle = atan2(sin_a, cos_a);

    // ── Structure angle: gentle differential shear for noise ──
    let shear = u.time_val * 0.05 / sqrt(r_norm);
    let angle_struct = base_angle + shear + u.orbit_angle;
    let cs = cos(angle_struct);
    let ss = sin(angle_struct);

    // ── Doppler beaming (fixed in camera frame) ──
    let fd_boost = u.spin * 0.3 / (r_norm * r_norm * r_norm);
    let v_orb = 0.45 * inverseSqrt(r_norm) + u.spin * 0.12 / (r_norm * r_norm);
    let raw_doppler = pow(max(1.0 + v_orb * cos(base_angle), 0.05), 3.0);
    let doppler = mix(1.0, raw_doppler, 0.6);

    // ── Temperature gradient (noise-perturbed for organic color variation) ──
    let t_warp = fbm(vec2<f32>(cs * 2.0 + ring_r * 1.5, ss * 1.5 + 50.0));
    let tc = clamp(t + (t_warp - 0.4) * 0.25, 0.0, 1.0);

    let inner_col = vec3<f32>(1.0, 0.95, 0.9);
    let mid1_col = vec3<f32>(1.0, 0.65, 0.3);
    let mid2_col = vec3<f32>(0.85, 0.3, 0.06);
    let outer_col = vec3<f32>(0.35, 0.04, 0.0);

    var base_col: vec3<f32>;
    if tc < 0.15 {
        base_col = mix(inner_col, mid1_col, tc / 0.15);
    } else if tc < 0.45 {
        base_col = mix(mid1_col, mid2_col, (tc - 0.15) / 0.3);
    } else {
        base_col = mix(mid2_col, outer_col, (tc - 0.45) / 0.55);
    }

    // Radial intensity
    let r_falloff = u.disk_glow * 0.5 / (r_norm * r_norm);

    // ── Domain-warped FBM density ──
    let warp_x = noise2d(vec2<f32>(cs * 2.0 + ring_r + 10.0, ss * 2.0 + 20.0)) - 0.5;
    let warp_y = noise2d(vec2<f32>(cs * 2.0 + ring_r + 30.0, ss * 2.0 + 40.0)) - 0.5;
    let wcs = cs + warp_x * 1.5;
    let wss = ss + warp_y * 1.5;

    // Large-scale: spiral arms, hot spots
    let density_large = fbm(vec2<f32>(
        wcs * 4.0 + wss * 3.0 + ring_r * 1.5,
        wss * 3.5 - wcs * 2.0 + 5.0,
    ));
    // Medium-scale: turbulent eddies, dark lanes
    let density_med = fbm(vec2<f32>(
        wcs * 8.0 + wss * 5.0 + ring_r * 2.0 + 15.0,
        wss * 6.0 + wcs * 3.0 + 25.0,
    ));

    let density = density_large * 0.55 + density_med * 0.45;
    let density_mod = smoothstep(0.15, 0.6, density);

    // Inner edge glow — wider spread for volumetric feel
    let inner_glow = exp(-(t * t) * 4.0) * 1.2;

    // Plunging region: gas inside ISCO spiraling into the hole.
    let plunge = max(1.0 - r_norm, 0.0);
    let redshift = exp(-plunge * 3.0);
    let plunge_col = vec3<f32>(0.8, 0.25, 0.03) * plunge * redshift * 2.0;

    var emission = base_col * r_falloff * doppler
        * (density_mod * 0.75 + 0.25)
        * (1.0 + inner_glow)
        + plunge_col;

    if is_secondary {
        emission *= 0.4;
    }

    // Hue-preserving emission cap. Instead of clamping r_norm or
    // hard-fading boundary pixels (both of which produce visible
    // step transitions and radial spikes from gaussian blur ripples),
    // bound the maximum brightness at the output and scale all
    // channels by the same ratio so warm color is preserved. The
    // shoulder is smooth so r_falloff's natural curve stays
    // continuous across the boundary — no spikes.
    let max_b = max(emission.r, max(emission.g, emission.b));
    let cap = 6.0;
    if max_b > cap {
        // Soft rolloff above cap — Reinhard-style asymptote
        let new_max = cap + (max_b - cap) / (1.0 + (max_b - cap) / cap);
        emission = emission * (new_max / max_b);
    }

    return emission;
}

// ── Main ──

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) gid: vec3<u32>) {
    let dims = textureDimensions(output);
    if gid.x >= dims.x || gid.y >= dims.y {
        return;
    }

    let uv = vec2<f32>(f32(gid.x) + 0.5, f32(gid.y) + 0.5)
        / vec2<f32>(f32(dims.x), f32(dims.y));

    // ── Sample pre-blurred deflection textures ──
    // The H+V separable gaussian compute passes already ran over the
    // deflection bake at quarter resolution, so by the time we get
    // here the textures contain a true 21-tap σ=4 gaussian-blurred
    // version of the deflection data. One bilinear tap each — the
    // entire wide-blur cost was paid at quarter-res.
    let d1 = textureSampleLevel(deflection1, s_linear, uv, 0.0);
    let d2 = textureSampleLevel(deflection2, s_linear, uv, 0.0);
    let sky = textureSampleLevel(sky_dir_tex, s_linear, uv, 0.0);

    let final_r = d1.r;
    let c1_r = d1.g;
    let c1_ca = d1.b;
    let c1_sa = d1.a;
    let c1_op = disk_opacity_from_r(c1_r);
    let c2_r = d2.g;
    let c2_ca = d2.b;
    let c2_sa = d2.a;

    // ── Star field background ──
    // sky.w is the escaped/absorbed flag from the deflection bake — 1.0
    // for rays that escaped, 0.0 for rays absorbed by the horizon. The
    // 5×5 gaussian above produces fractional values across the shadow
    // boundary; smoothstep gives a soft shadow edge instead of a hard
    // pixelated cutoff. The previous `if sky.w > 0.3` was the source
    // of the "blocky shadow" — the gaussian was working, we were just
    // re-thresholding it back into a binary signal.
    var color = vec3<f32>(0.0);
    let escape_w = smoothstep(0.15, 0.65, sky.w);
    if escape_w > 0.001 {
        color = star_field(normalize(sky.xyz), u.stars_brightness) * escape_w;
    }
    var total_opacity = 0.0;

    // ── First crossing (front disk) ──
    // c1_mag2 = squared magnitude of (cos_a, sin_a) — ~1.0 for a real
    // crossing, 0 for a non-crossing pixel. The 5×5 gaussian blur over
    // the quarter-res deflection bake produces fractional values at
    // boundaries; smoothstep gives a soft silhouette edge so the disk
    // fades into the star field instead of cutting hard.
    let c1_mag2 = c1_ca * c1_ca + c1_sa * c1_sa;
    let c1_visible = smoothstep(0.25, 0.85, c1_mag2);
    let c1_op_eff = c1_op * c1_visible;
    if c1_r > 0.1 && c1_op_eff > 0.001 {
        var disk_col = shade_disk(c1_r, c1_ca, c1_sa, false) * c1_op_eff;
        if u.particle_strength > 0.001 {
            // First crossing is the front disk — bias toward the top layer.
            // Clamp the boost so polar cell clumps can't produce extreme
            // wedge spikes that ACES can't compress without losing color.
            let d1 = sample_particle_density(c1_r, c1_ca, c1_sa, 1.0);
            let boost = min(d1 * u.particle_strength * 2.5, 1.2);
            disk_col = disk_col * (1.0 + boost);
        }
        color = color * (1.0 - c1_op_eff * 0.85) + disk_col;
        total_opacity = c1_op_eff;
    }

    // ── Second crossing (lensed back) ──
    let c2_mag2 = c2_ca * c2_ca + c2_sa * c2_sa;
    let c2_visible = smoothstep(0.25, 0.85, c2_mag2);
    if c2_r > 0.1 && c2_visible > 0.001 {
        let c2_op = disk_opacity_from_r(c2_r) * c2_visible;
        let remaining = max(1.0 - total_opacity * 0.6, 0.0);
        var disk_col = shade_disk(c2_r, c2_ca, c2_sa, true) * c2_op * remaining;
        if u.particle_strength > 0.001 {
            // Second crossing is the lensed back of the disk — bias toward bottom.
            let d2v = sample_particle_density(c2_r, c2_ca, c2_sa, 0.0);
            let boost = min(d2v * u.particle_strength * 2.5, 1.2);
            disk_col = disk_col * (1.0 + boost);
        }
        color = color * (1.0 - c2_op * remaining * 0.5) + disk_col;
        total_opacity = clamp(total_opacity + c2_op * 0.5, 0.0, 1.0);
    }

    // ── Photon ring (visible even over disk, softens shadow boundary) ──
    if final_r > 1.0 && final_r < 5.0 {
        let ring = exp(-(final_r - 1.5) * (final_r - 1.5) * 6.0);
        let ring_vis = ring * mix(0.6, 0.15, clamp(total_opacity, 0.0, 1.0));
        color += vec3<f32>(0.9, 0.85, 0.7) * ring_vis;
    }

    // ── Volumetric emission (path integral through disk atmosphere) ──
    // The deflection bake stores `vol_accum` — a Gaussian-weighted line
    // integral of the disk's vertical thickness profile along the ray.
    // BUT vol_accum is non-zero for any ray that passes near the disk
    // plane, even rays that miss the disk entirely (because the
    // Gaussian half-thickness extends in y by 0.12*r). Then the
    // gaussian blur on d2.r smears those values further outward,
    // producing a soft warm halo around the disk that becomes obvious
    // when stars are bright (high contrast with the dark sky behind).
    //
    // Gate vol_emit by c1_visible so it only contributes where the
    // ray actually crosses the disk silhouette.
    let vol = d2.r;
    if vol > 0.01 && c1_visible > 0.001 {
        let vol_opacity = 1.0 - exp(-vol * 0.3);
        let vol_r = select(c1_r, (u.disk_inner + u.disk_outer) * 0.5, c1_r < 0.1);
        let vol_t = clamp(
            (vol_r - u.disk_inner) / (u.disk_outer - u.disk_inner), 0.0, 1.0);
        let vol_col = mix(
            vec3<f32>(1.0, 0.85, 0.6),
            vec3<f32>(0.5, 0.12, 0.02),
            vol_t,
        );
        let vol_fade = smoothstep(0.0, 0.15, vol);
        var vol_emit = vol_col * vol_opacity * vol_fade * u.disk_glow * 0.15
            * c1_visible;
        if u.particle_strength > 0.001 && c1_r > 0.1 && c1_mag2 > 0.25 {
            // Sample both layers symmetrically — volumetric emission spans
            // the full disk thickness, so neither side is "near" or "far".
            let dv = sample_particle_density(c1_r, c1_ca, c1_sa, 0.5);
            let boost = min(dv * u.particle_strength * 2.0, 1.0);
            vol_emit = vol_emit * (1.0 + boost);
        }
        color += vol_emit;
    }

    // ── HDR output ──
    // No tonemapping in this shader. The output buffer is Rgba16Float
    // and the rest of the MANIFOLD pipeline (bloom prefilter at 0.42,
    // halation, EDR display presenter) is fully HDR-aware. Bright
    // disk regions are emitted with R/G/B values well above 1.0; bloom
    // catches them as highlights and EDR displays them at cinematic
    // brightness. Tonemapping inside this shader was the source of
    // the white-blowout bug — it pre-compressed every value down to
    // ~1.0 and forced channel saturation to converge on (1,1,1).
    //
    // Sanity floor only — guard against any NaN or negative leakage.
    color = max(color, vec3<f32>(0.0));

    textureStore(output, gid.xy, vec4<f32>(color, 1.0));
}
